import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom'; // Import useNavigate
import './Settings.css';

function Settings() {
  const [Id, setId] = useState('');
  const [domain, setDomain] = useState('');
  const [username, setJiraUsername] = useState('');
  const [apiToken, setJiraApiToken] = useState('');
  const [locked, setLocked] = useState(true);
  const [details, setDetails] = useState([]);
  const [credentials, setCredentials] = useState([]);
  const [checkedDetails, setCheckedDetails] = useState([]); // Track selected details
  const [checkedCredentials, setCheckedCredentials] = useState([]); // Track selected credentials
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const navigate = useNavigate(); // Initialize navigate

  // Fetch details from the server
  const fetchDetails = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('https://localhost:7216/api/Auth/details');
      if (!response.ok) {
        throw new Error('Failed to fetch credentials');
      }
      const data = await response.json();
      setDetails(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchDetails();
  }, []);

  // Fetch details from the server
  const fetchCredentials = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('https://localhost:7216/api/Auth/credentials');
      if (!response.ok) {
        throw new Error('Failed to fetch credentials');
      }
      const data = await response.json();
      setCredentials(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCredentials();
  }, []);

  // Toggle the locked/unlocked state of input fields
  const handleLockToggle = () => {
    setLocked(!locked);
  };

  // Delete a detail
  const handleDeleteDetail = async (id) => {
    try {
      const response = await fetch(`https://localhost:7216/api/Auth/delete/${id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        setDetails(details.filter((cred) => cred.id !== id));
        setCheckedDetails([]); // Reset checked credentials after deletion
      } else {
        throw new Error('Failed to delete credential');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  // Delete a detail
  const handleDeleteCredential = async (id) => {
    try {
      const response = await fetch(`https://localhost:7216/api/Auth/delete/${id}`, {
        method: 'DELETE',
      });
      if (response.ok) {
        setCredentials(details.filter((cred) => cred.id !== id));
        setCheckedCredentials([]); // Reset checked credentials after deletion
      } else {
        throw new Error('Failed to delete credential');
      }
    } catch (err) {
      setError(err.message);
    }
  };

  // Handle checkbox changes
  const handleCheckboxChange = (id) => {
    if (checkedDetails.includes(id)) {
      setCheckedDetails(checkedDetails.filter((checkboxId) => checkboxId !== id));
    } else {
      setCheckedDetails([...checkedDetails, id]);
    }
  };

  // Save the new credentials
  const handleSave = async () => {
    if (!domain || !username || !apiToken) {
      setError('All fields are required.');
      return;
    }

    const newCredential = { Id, domain, username, apiToken };

    setLoading(true);
    setError(null);

    try {
      const response = await fetch('https://localhost:7216/api/Auth/save', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newCredential),
      });

      if (!response.ok) {
        throw new Error('Failed to save credential');
      }

      const savedCredential = await response.json();
      setDetails([...details, savedCredential]);
      setId('');
      setDomain('');
      setJiraUsername('');
      setJiraApiToken('');
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  // Handle the "Load" action
  const handleLoad = () => {
    if (checkedDetails.length === 1) {
      const selectedCredential = details.find((cred) => checkedDetails.includes(cred.id));
      if (selectedCredential) {
        navigate('/chatbox', { state: { selectedCredential } });
      }
    }
  };

  return (
    <div className="settings-container">
      <h2>Jira Settings</h2>
      {error && <div className="error">{error}</div>}

      <div className="credentials-form">
        <div className="field">
          <label>Id</label>
          <input
            type="text"
            value={Id}
            onChange={(e) => setId(e.target.value)}
            disabled={locked}
          />
          <label>Domain</label>
          <input
            type="text"
            value={domain}
            onChange={(e) => setDomain(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira Username</label>
          <input
            type="text"
            value={username}
            onChange={(e) => setJiraUsername(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="field">
          <label>Jira API Token</label>
          <input
            type="password"
            value={apiToken}
            onChange={(e) => setJiraApiToken(e.target.value)}
            disabled={locked}
          />
        </div>

        <div className="button-container">
          <button className="save-button" onClick={handleSave} disabled={locked}>
            Save
          </button>
          <div className="lock-checkbox">
            <input
              type="checkbox"
              checked={!locked}
              onChange={handleLockToggle}
            />
            <label>{locked ? 'Unlock Fields' : 'Lock Fields'}</label>
          </div>
          <button
            className="load-button"
            onClick={handleLoad}
            disabled={checkedDetails.length !== 1} // Disable until one checkbox is selected
          >
            Load
          </button>
        </div>
      </div>

      <div className="credentials-list">
        <h3>Stored Credentials</h3>
        {loading ? (
          <div className="loading">Loading...</div>
        ) : (
          <div className="table-container">
            <table className="credentials-table">
              <thead>
                <tr>
                  <th>Select</th>
                  <th>Domain</th>
                  <th>Username</th>
                  <th>ApiToken</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {details.map((cred) => (
                  <tr key={cred.id}>
                    <td>
                      <input
                        type="checkbox"
                        checked={checkedDetails.includes(cred.id)}
                        onChange={() => handleCheckboxChange(cred.id)}
                      />
                    </td>
                    <td>{cred.domain}</td>
                    <td>{cred.username}</td>
                    <td>{cred.apiToken ? `${cred.apiToken.slice(0, 4)}****` : 'No Token'}</td>
                    <td>
                      <button 
                        onClick={() => handleDeleteDetail(cred.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
      <div className="Signup-list">
        <h3>Stored Signups</h3>
        {loading ? (
          <div className="loading">Loading...</div>
        ) : (
          <div className="table-container">
            <table className="credentials-table">
              <thead>
                <tr>
                  <th>Select</th>
                  <th>Id</th>
                  <th>Email</th>
                  <th>Password</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {credentials.map((cred) => (
                  <tr key={cred.id}>
                    <td>
                      <input
                        type="checkbox"
                        checked={checkedCredentials.includes(cred.id)}
                        onChange={() => handleCheckboxChange(cred.id)}
                      />
                    </td>
                    <td>{cred.Id}</td>
                    <td>{cred.Email}</td>
                    <td>{cred.Password ? `${cred.apiToken.slice(0, 4)}****` : 'No Token'}</td>
                    <td>
                      <button 
                        onClick={() => handleDeleteCredential(cred.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

export default Settings;
